import os
for root, dirs, files in os.walk('/workspace'):
    # skip memory dirs and trajectory subdirs
    depth = root.count('/') - 1
    if depth > 3: continue
    for f in files:
        p = os.path.join(root, f)
        try:
            sz = os.path.getsize(p)
        except: sz = -1
        if sz < 5_000_000:
            print(p, sz)
